mapper.select:
/* 대화방 소유자 검증 ai.chatbot.countChatRoomOwnedByUser */
SELECT COUNT(1)
FROM TB_CHAT_ROOM A
WHERE A.ROOM_ID = #{roomId}
  AND A.CREATE_USER_ID = #{userId}

/* 공유 토큰 존재 여부 (만료 여부 판별용) ai.chatbot.countShareTokenByToken */
SELECT COUNT(1)
FROM TB_SHARE_TOKEN T
WHERE T.SHARE_TOKEN = #{shareToken}

mapper.update:
/* CHAT 대화방 마지막 채팅 일시 업데이트 ai.chatbot.updateChatRoomLastChatDt */
UPDATE TB_CHAT_ROOM
SET LAST_CHAT_DT = NOW()
WHERE ROOM_ID = #{roomId}

/* CHAT 대화방 만족도 조회 ai.chatbot.selectSatisYn */
UPDATE TB_CHAT_LOG
SET SATIS_YN = #{satisYn}
    , SATIS_CONTENT = #{satisContent}
    , SATIS_CD = #{satisCd}
    , SATIS_DT = NOW()
WHERE LOG_ID = #{logId}

/* 채팅방 고정 ai.chatbot.updatePinChatRoom */
UPDATE TB_CHAT_ROOM
SET FIX_YN = CASE WHEN FIX_YN = 'Y' THEN 'N' ELSE 'Y' END
WHERE ROOM_ID = #{roomId}

/* 채팅방 제목 수정 ai.chatbot.updateChatRoomTitle */
UPDATE TB_CHAT_ROOM
SET ROOM_TITLE = #{roomTitle}
WHERE ROOM_ID = #{roomId}

mapper.delete:
/* 채팅방 삭제 ai.chatbot.deleteChatRoom */
DELETE FROM TB_CHAT_ROOM
WHERE ROOM_ID = #{roomId}

/* 채팅 로그 삭제 ai.chatbot.deleteChatLog */
DELETE FROM TB_CHAT_LOG
WHERE ROOM_ID = #{roomId}

mapper.select:
/* 지식 카드 최대 정렬 순서 조회 ai.chatbot.selectMaxSortOrd */
SELECT IFNULL(MAX(A.SORT_ORD), 0)
FROM TB_KNOW_CARD A
WHERE A.USER_ID = #{userId}
  AND A.CATEGORY_ID = #{categoryId}

mapper.update:
/* 지식 카드 맨 앞 등록을 위한 정렬 순서 증가 ai.chatbot.updateKnowledgeSortOrdForPrepend */
UPDATE TB_KNOW_CARD
SET SORT_ORD = SORT_ORD + 1
    , MODIFY_DT = NOW()
WHERE USER_ID = #{userId}
  AND CATEGORY_ID = #{categoryId}

/* 첨부파일 LOG_ID 연결 ai.chatbot.updateChatFileLogId */
UPDATE TB_CHAT_FILE
SET LOG_ID = #{logId}
WHERE CHAT_FILE_ID IN

    #{id}

AND LOG_ID IS NULL

/* 채팅 파일 orphan 처리 ai.chatbot.updateChatFileOrphan */
UPDATE TB_CHAT_FILE
SET FILE_EXIST_YN = 'N'
WHERE CHAT_FILE_ID IN

    #{id}

AND LOG_ID IS NULL

mapper.select:
/* 채팅 첨부 단건 조회 (대화방 소유 + 첨부 업로더 일치 또는 구데이터 호환) ai.chatbot.selectChatFileOwnedByUser */
SELECT
    F.CHAT_FILE_ID AS chatFileId,
    F.FILE_PATH AS filePath,
    F.FILE_NAME AS fileName,
    F.FILE_TYPE AS fileType
FROM TB_CHAT_FILE F
INNER JOIN TB_CHAT_ROOM R ON F.ROOM_ID = R.ROOM_ID
WHERE F.CHAT_FILE_ID = #{chatFileId}
  AND R.CREATE_USER_ID = #{userId}
  AND (
      F.CREATE_USER_ID = #{userId}
      OR F.CREATE_USER_ID IS NULL
  )

mapper.insert:
/* 뉴스 관심 카테고리 저장 ai.chatbot.upsertUserNewsInterestCategories — UK(USER_ID), 목록은 NEWS_CATEGORY_CD JSON */
INSERT INTO TB_USER_INTEREST_NEWS_CATEGORY (
    NEWSCG_ID
    , USER_ID
    , NEWS_CATEGORY_CD
    , CREATE_DT
    , MODIFY_DT
) VALUES (
    #{newscgId}
    , #{userId}
    , #{newsCategoryCd}
    , NOW()
    , NOW()
)
ON DUPLICATE KEY UPDATE
    NEWS_CATEGORY_CD = VALUES(NEWS_CATEGORY_CD)
    , MODIFY_DT = NOW()

mapper.delete:
/* 챗봇 첨부파일 DB 삭제 ai.chatbot.deleteChatFile */
DELETE
FROM TB_CHAT_FILE
WHERE CHAT_FILE_ID = #{chatFileId}
